+package github.chains;
+
+import spoon.Launcher;
+import spoon.processing.AbstractProcessor;
+import spoon.reflect.declaration.CtTypeReference;
+
+public class Main {
+
+    private static final String OLD_TYPE = "net.lingala.zip4j.core.ZipFile";
+
+    private static final String NEW_TYPE = "net.lingala.zip4j.ZipFile";
+
+    public static void main(String[] args) {
+        if (args.length != 2) {
+            throw new IllegalArgumentException("Usage: <input-source-dir> <output-source-dir>");
+        }
+
+        Launcher launcher = new Launcher();
+        launcher.addInputResource(args[0]);
+        launcher.setSourceOutputDirectory(args[1]);
+        launcher.getEnvironment().setNoClasspath(true);
+        launcher.getEnvironment().setAutoImports(true);
+
+        launcher.addProcessor(new AbstractProcessor<CtTypeReference<?>>() {
+            @Override
+            public boolean isToBeProcessed(CtTypeReference<?> candidate) {
+                return OLD_TYPE.equals(candidate.getQualifiedName());
+            }
+
+            @Override
+            public void process(CtTypeReference<?> candidate) {
+                candidate.setQualifiedName(NEW_TYPE);
+            }
+        });
+
+        launcher.run();
+    }
+}
*** End Patch

